export const LayoutContext = createContext();

const Layout = ({ children }) => {
 
  return (
    <LayoutContext.Provider value={{ data, dispatch }}>
      <Fragment>
        <div className="flex-grow">
          <Navber />
          <LoginSignup />
          <CartModal />
          {children}
        </div>
        <Footer />
      </Fragment>
    </LayoutContext.Provider>
  );
};


export default Layout;
